19	static help_colors help_make_colors(FILE *fp) {
20	    bool color = isatty(fileno(fp));
21	    help_colors c = {0};
22	    if (!color) return c;
23	    c.off = "\x1b[0m";
24	    c.cyan = "\x1b[38;5;81m";
25	    c.title = "\x1b[1;38;5;250m";
26	    c.yellow = "\x1b[38;5;179m";
27	    c.grey = "\x1b[38;5;240m";
28	    c.red = "\x1b[38;5;203m";
29	    c.white = "\x1b[38;5;252m";
30	    c.bright = "\x1b[1;38;5;231m";
31	    return c;
32	}
