42	static bool option_name_has_switch(const char *name) {
43	    bool word_start = true;
44	    while (*name) {
45	        if (word_start && (*name == '-' || *name == '/')) return true;
46	        word_start = (*name == ' ');
47	        name++;
48	    }
49	    return false;
50	}
51	
52	static void print_colored_option_name(FILE *fp, const help_colors *c, const char *name) {
53	    bool has_switch = option_name_has_switch(name);
54	    bool word_start = true;
55	    while (*name) {
56	        const char *start = name;
57	        while (*name && *name != ' ') name++;
58	        bool is_option = !has_switch || *start == '-' || *start == '/' ||
59	                         (word_start && has_switch && *start != '[');
60	        const char *color = is_option ? c->cyan : c->bright;
61	        if (color) fputs(color, fp);
62	        fwrite(start, 1, (size_t)(name - start), fp);
63	        if (color && c->off) fputs(c->off, fp);
64	        if (*name == ' ') {
65	            fputc(*name++, fp);
66	            word_start = false;
67	        }
68	    }
69	}
70	
71	static void opt(FILE *fp, const help_colors *c, const char *name, const char *desc) {
72	    if (c->cyan) {
73	        fputs("  ", fp);
74	        print_colored_option_name(fp, c, name);
75	        fprintf(fp, " %s|%s ", c->grey ? c->grey : "", c->grey ? c->off : "");
76	        fprintf(fp, "%s%s%s\n", c->white ? c->white : "", desc,
77	                c->white ? c->off : "");
78	        return;
79	    }
80	
81	    const int col = 30;
82	    int n = (int)strlen(name);
83	    if (n > col) {
84	        fprintf(fp, "  %s\n      %s\n", name, desc);
85	    } else {
86	        fprintf(fp, "  %-30s %s\n", name, desc);
87	    }
88	}
