104	    switch (tool) {
105	    case DS4_HELP_DS4: return "ds4";
106	    case DS4_HELP_SERVER: return "ds4-server";
107	    case DS4_HELP_AGENT: return "ds4-agent";
108	    case DS4_HELP_BENCH: return "ds4-bench";
109	    case DS4_HELP_EVAL: return "ds4-eval";
110	    }
