146	static void print_model_runtime(FILE *fp, const help_colors *c,
147	                                ds4_help_tool tool, bool full) {
148	    title(fp, c, "Model And Runtime");
149	    opt(fp, c, "-m, --model FILE", "GGUF model path. Default: ds4flash.gguf");
150	#ifdef DS4_ROCM_BUILD
151	    opt(fp, c, "--metal | --rocm | --cpu", "Select the backend explicitly.");
152	    opt(fp, c, "--backend NAME", "Backend name: metal, rocm, or cpu.");
153	#else
154	    opt(fp, c, "--metal | --cuda | --cpu", "Select the backend explicitly.");
155	    opt(fp, c, "--backend NAME", "Backend name: metal, cuda, or cpu.");
156	#endif
157	    if (tool != DS4_HELP_BENCH) {
158	        opt(fp, c, "-c, --ctx N", "Allocated context tokens.");
159	    }
160	    if (tool == DS4_HELP_SERVER) {
161	        opt(fp, c, "-n, --tokens N", "Default max output tokens when clients omit a limit.");
162	    }
163	    opt(fp, c, "-t, --threads N", "CPU helper threads for host-side/reference work.");
164	    opt(fp, c, "--power N", "GPU duty-cycle target, 1..100. Default: 100");
165	    opt(fp, c, "--ssd-streaming", "Metal/CUDA/ROCm: opt in to SSD-backed model streaming instead of full residency.");
166	    opt(fp, c, "--ssd-streaming-cold", "SSD streaming: skip default popularity-based expert-cache preload.");
167	    opt(fp, c, "--ssd-streaming-cache-experts N|NGB", "SSD streaming: routed expert cache as expert count or GiB, e.g. 32GB. Metal/ROCm default: 80% working set minus non-routed weights; CUDA default: backend fixed cache.");
168	    opt(fp, c, "--ssd-streaming-preload-experts N", "SSD streaming: upfront popularity preload count. Default: auto hot seed capped at 4096; use --ssd-streaming-cold to skip.");
169	    opt(fp, c, "--simulate-used-memory NGB", "Diagnostic: lock N GiB before model load to simulate a smaller-memory machine.");
170	    opt(fp, c, "--prefill-chunk N", "Metal graph prefill chunk size. Default: auto (PRO long prompts use 8192; others use 4096).");
171	    if (full) {
172	        if (tool != DS4_HELP_BENCH) {
173	            opt(fp, c, "--mtp FILE", "Optional MTP support GGUF used for draft-token probes.");
174	        }
175	        if (tool == DS4_HELP_DS4 || tool == DS4_HELP_AGENT || tool == DS4_HELP_SERVER) {
176	            opt(fp, c, "--mtp-draft N", "Maximum autoregressive MTP draft tokens. Default: 1");
177	            opt(fp, c, "--mtp-margin F", "Verifier confidence margin for fast MTP acceptance. Default: 3");
178	        }
179	        opt(fp, c, "--quality", "Prefer exact kernels where faster approximate paths exist.");
180	        opt(fp, c, "--warm-weights", "Touch mapped tensor pages at startup to reduce first-use stalls.");
181	        if (tool == DS4_HELP_DS4 || tool == DS4_HELP_BENCH) {
182	            opt(fp, c, "--expert-profile FILE", "Metal-only: write routed expert locality/cache simulation JSON.");
183	        }
184	    }
185	    fputc('\n', fp);
186	}
