372	static bool tool_has_topic(ds4_help_tool tool, const char *topic) {
373	    if (!topic) return true;
374	    if (streq(topic, "all")) return true;
375	    if (streq(topic, "runtime") || streq(topic, "distributed")) return true;
376	    if (streq(topic, "sampling"))
377	        return tool == DS4_HELP_DS4 || tool == DS4_HELP_AGENT || tool == DS4_HELP_EVAL;
378	    if (streq(topic, "steering"))
379	        return tool == DS4_HELP_DS4 || tool == DS4_HELP_SERVER || tool == DS4_HELP_AGENT;
380	    switch (tool) {
381	    case DS4_HELP_DS4:
382	        return streq(topic, "diagnostics") || streq(topic, "commands");
383	    case DS4_HELP_SERVER:
384	        return streq(topic, "api") || streq(topic, "kv-cache") || streq(topic, "thinking");
385	    case DS4_HELP_AGENT:
386	        return streq(topic, "sessions") || streq(topic, "commands") || streq(topic, "tools");
387	    case DS4_HELP_BENCH:
388	        return streq(topic, "benchmark");
389	    case DS4_HELP_EVAL:
390	        return streq(topic, "evaluation");
391	    }
392	    return false;
393	}
