395	static void more_line(FILE *fp, const help_colors *c, const char *label, const char *topic) {
396	    static const char *colors[] = {
397	        "\x1b[38;5;81m", "\x1b[38;5;114m", "\x1b[38;5;179m",
398	        "\x1b[38;5;141m", "\x1b[38;5;147m"
399	    };
400	    static size_t idx;
401	    const char *on = c->cyan ? colors[idx++ % (sizeof(colors) / sizeof(colors[0]))] : "";
402	    if (streq(label, "Interactive commands:") && c->red) on = c->red;
403	    const char *off = c->off ? c->off : "";
404	    fprintf(fp, "    %s%-26s%s --help %s\n", on, label, off, topic);
405	}
