407	static void print_more_info(FILE *fp, const help_colors *c, ds4_help_tool tool) {
408	    title(fp, c, "More Info");
409	    more_line(fp, c, "Runtime full info:", "runtime");
410	    if (tool_has_topic(tool, "sampling"))
411	        more_line(fp, c, "Sampling full info:", "sampling");
412	    more_line(fp, c, "Distributed inference:", "distributed");
