1	#include "ds4.h"
2	#include "ds4_distributed.h"
3	#include "ds4_help.h"
4	#include "linenoise.h"
5	
6	/* ds4 CLI.
7	 *
8	 * One-shot mode builds a single DeepSeek chat prompt and exits.  Interactive
9	 * mode keeps a rendered token transcript plus one ds4_session, so follow-up
10	 * turns reuse the live Metal KV checkpoint just like the server does.  The CLI
11	 * deliberately keeps policy here and leaves graph/cache mechanics inside the
12	 * engine API. */
13	
